# CI linter: every page alert must carry a resolvable runbook_url
import sys, yaml, urllib.request

def lint(rule_files):
    failures = []
    for path in rule_files:
        spec = yaml.safe_load(open(path))
        for group in spec.get("groups", []):
            for rule in group.get("rules", []):
                if rule.get("labels", {}).get("severity") != "page":
                    continue
                url = rule.get("annotations", {}).get("runbook_url")
                name = rule.get("alert", "<unknown>")
                if not url:
                    failures.append(f"{name}: missing runbook_url")
                    continue
                try:
                    status = urllib.request.urlopen(url, timeout=5).status
                    if status >= 400:
                        failures.append(f"{name}: runbook returned {status}")
                except Exception as e:
                    failures.append(f"{name}: runbook unreachable ({e})")
    if failures:
        print("\n".join(failures)); sys.exit(1)
    print("All page alerts have valid runbooks")

# Scheduled review-date checker: file tickets for stale runbooks
from datetime import datetime, timezone, timedelta
import re

MAX_AGE = timedelta(days=120)

def parse_metadata(markdown: str):
    owner = re.search(r"\*\*Owner:\*\*\s*(\S+)", markdown)
    reviewed = re.search(r"\*\*Last reviewed:\*\*\s*(\d{4}-\d{2}-\d{2})", markdown)
    return (owner.group(1) if owner else None,
            reviewed.group(1) if reviewed else None)

def check_runbook(path: str, markdown: str):
    owner, reviewed = parse_metadata(markdown)
    issues = []
    if not owner:
        issues.append("missing Owner metadata")
    if not reviewed:
        issues.append("missing Last reviewed date")
    else:
        age = datetime.now(timezone.utc) - datetime.fromisoformat(
            reviewed).replace(tzinfo=timezone.utc)
        if age > MAX_AGE:
            issues.append(f"stale: reviewed {age.days}d ago (max {MAX_AGE.days})")
    return {"path": path, "owner": owner, "issues": issues}
